Fix WalletContext.approveTopUp (and rejectTopUp for consistency) so it can operate on a transaction that was just created in the same render cycle. Recommended: refactor to use functional setState, e.g.:

  const approveTopUp = useCallback((id) => {
    let found;
    setTransactions(prev => {
      found = prev.find(t => t.id === id);
      if (!found || found.type !== 'topup' || found.status !== 'pending') return prev;
      return prev.map(t => t.id === id ? { ...t, status: 'approved', updatedAt: nowIso() } : t);
    });
    if (!found) return { ok: false, reason: 'المعاملة غير موجودة' };
    setWallet(prev => ({ ...prev, balance: prev.balance + found.amount, updatedAt: nowIso() }));
    return { ok: true, transaction: { ...found, status: 'approved' } };
  }, []);

This removes the dependency on the stale `transactions` closure.
